import{r as n,o as d,c as u,a as s,b as a,w as l,F as i,e,d as t}from"./app.d438baca.js";import{_ as p}from"./plugin-vue_export-helper.21dcd24c.js";const c={},h=s("h1",{id:"update-thunder-6-thunder-7",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#update-thunder-6-thunder-7","aria-hidden":"true"},"#"),e(" Update Thunder 6 -> Thunder 7")],-1),m=s("h2",{id:"prerequisites",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#prerequisites","aria-hidden":"true"},"#"),e(" Prerequisites")],-1),b=e("These are the instructions to manually update your existing Thunder 6 installation to Thunder 7. If you want to do a fresh installation of thunder please visit "),v=e("install Thunder"),g=e("."),_=t(`<p><strong>The most important changes are that we switched from our own &quot;Thunder Admin&quot; theme to the Gin theme and also replaced the Entity Browser module by the Media Library that is provided by Drupal core.</strong></p><p>You have to make sure that your Thunder 6 project and all its dependencies are fully updated to the most current versions. Run the following command in your docroot:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>drush ev <span class="token string">&quot;print drupal_get_installed_schema_version(&#39;thunder&#39;) . PHP_EOL;&quot;</span>
</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>This should print the number 8326 or greater. If that is not the case, update your project.</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> <span class="token punctuation">..</span>
<span class="token function">composer</span> update
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>This should update to Thunder 6.3 or greater.</p><p>Now run database updates:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> docroot
drush updb
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>You should at least see the Thunder 8326 schema update. If not, double check that the correct version of Thunder is installed, and that <code>drush updb</code> did not throw any errors.</p><p>Before you start with the code and database update please add the Entity Browser module, the Shariff module, and the Thunder Admin theme to your own composer.json. Both are no longer part of Thunder and can be removed after the update was successfully executed. Also the ckeditor module and the seven theme are needed for the update process.</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">composer</span> require drupal/entity_browser drupal/thunder_admin drupal/shariff drupal/ckeditor drupal/seven
</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>Also, if you have the liveblog, better_normalizers, google_analytics, ctools or adsense module enabled, you have to require them own your own, since Thunder removed them from the distribution.</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">composer</span> require drupal/liveblog
<span class="token function">composer</span> require drupal/better_normalizers
<span class="token function">composer</span> require drupal/adsense
<span class="token function">composer</span> require drupal/google_analytics
<span class="token function">composer</span> require drupal/ctools
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Thunder&#39;s new default frontend theme is Olivero, and we removed Thunder Base which was based on the Bartik theme, which was removed from Drupal 10 as well. In case you use Thunder Base as your theme, you have to switch to a different one before updating. We recommend to switch to Olivero as well.</p>`,14),f=e("In Thunder 7 we also upgraded the simple_sitemap module from version 3 to version 4. If your project has custom plugins, you have to update them to the new version. See the "),y={href:"https://gbyte.dev/blog/simple-xml-sitemap-4-0-has-been-released?language_content_entity=und",target:"_blank",rel:"noopener noreferrer"},w=e("simple_sitemap documentation"),k=e("."),x=t(`<h2 id="execute-the-update" tabindex="-1"><a class="header-anchor" href="#execute-the-update" aria-hidden="true">#</a> Execute the update</h2><p>All you need to do now is:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">composer</span> require thunder/thunder-distribution:~7.0@STABLE --no-update
<span class="token function">composer</span> update

drush updb
drush cr
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>After the update was executed successfully, you can remove the outdated extensions.</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">composer</span> remove drupal/entity_browser drupal/thunder_admin
</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div>`,5);function T(q,B){const r=n("RouterLink"),o=n("ExternalLinkIcon");return d(),u(i,null,[h,m,s("p",null,[b,a(r,{to:"/developer-guide/setup.html#install-thunder"},{default:l(()=>[v]),_:1}),g]),_,s("p",null,[f,s("a",y,[w,a(o)]),k]),x],64)}var A=p(c,[["render",T]]);export{A as default};
